        require(id < _candidateCount, "Invalid candidate ID");
        return candidates[id].votes;
    }

    function addCandidate(string memory name) public onlyOwner {
        require(_candidateCount < 100, "Max candidate limit reached");
        candidates[_candidateCount] = Candidate(keccak256(abi.encodePacked(name)), 0);
        _candidateCount++;
    }

    function grantVotingRights(address voter) public onlyOwner {
        voters[voter] = true;
    }

    function revokeVotingRights(address voter) public onlyOwner {
        voters[voter] = false;
    }

    function hasVotingRights(address voter) public view returns (bool) {
        return voters[voter];
    }

    function vote(uint256 candidateId) public {
        require(candidateId > 0, "Invalid candidate ID");
        require(candidateId <= _candidateCount, "Invalid candidate ID");
        require(hasVotingRights(msg.sender), "No voting rights");
        require(!voted[msg.sender], "Already voted");

        voted[msg.sender] = true;
        candidates[candidateId - 1].votes++;
    }
}
